import type { ActiveLocale } from "@/config/locales";
import { PlaceholderPage } from "@/features/content/components/PlaceholderPage";

const meta: Record<ActiveLocale, { title: string; description: string }> = {
  pt: { title: "Artigos sobre Bolor e Humidade — MoldCheck.pt", description: "Artigos editoriais independentes sobre bolor, humidade e qualidade do ar interior em Portugal." },
  en: { title: "Articles on Mold and Damp — MoldCheck.pt", description: "Independent editorial articles on mold, damp and indoor air quality in Portugal." },
  fr: { title: "Articles sur les Moisissures — MoldCheck.pt", description: "Articles éditoriaux indépendants sur les moisissures, l'humidité et la qualité de l'air intérieur au Portugal." },
  de: { title: "Artikel über Schimmel — MoldCheck.pt", description: "Unabhängige redaktionelle Artikel über Schimmel, Feuchtigkeit und Innenraumluftqualität in Portugal." },
  nl: { title: "Artikelen over Schimmel — MoldCheck.pt", description: "Onafhankelijke redactionele artikelen over schimmel, vocht en binnenluchtkwaliteit in Portugal." },
  it: { title: "Articoli su Muffa e Umidità — MoldCheck.pt", description: "Articoli editoriali indipendenti su muffa, umidità e qualità dell'aria interna in Portogallo." },
  es: { title: "Artículos sobre Moho y Humedad — MoldCheck.pt", description: "Artículos editoriales independientes sobre moho, humedad y calidad del aire interior en Portugal." },
};

export async function generateMetadata({ params }: { params: Promise<{ locale: ActiveLocale }> }) {
  const { locale } = await params;
  return meta[locale] ?? meta.en;
}

export default function ArticlesPage() {
  return <PlaceholderPage eyebrow="Editorial" title="Articles" description="Articles index scaffold." />;
}
